-- Manual test data for local development.
-- Load this AFTER running Flyway migrations.
-- Default password for all demo users: password123

-- Example:
--   psql postgresql://ktor_user:ktor_password@localhost:5432/ktor_sample \
--     -f backend/src/main/resources/db/manual-test-data.sql

TRUNCATE TABLE comments, article_tags, favorites, follows, articles, tags, users RESTART IDENTITY CASCADE;

SELECT setval(pg_get_serial_sequence('users', 'user_id'), (SELECT COALESCE(MAX(user_id), 1) FROM users), true);
SELECT setval(pg_get_serial_sequence('tags', 'tag_id'), (SELECT COALESCE(MAX(tag_id), 1) FROM tags), true);
SELECT setval(pg_get_serial_sequence('articles', 'article_id'), (SELECT COALESCE(MAX(article_id), 1) FROM articles), true);
SELECT setval(pg_get_serial_sequence('comments', 'comment_id'), (SELECT COALESCE(MAX(comment_id), 1) FROM comments), true);
