INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (1, 'shipping-a-kotlin-multiplatform-app', 'Shipping a Kotlin Multiplatform App', 'What worked, what hurt, and what I would do differently.', 'We built a Kotlin Multiplatform client for the RealWorld demo app and learned a few practical lessons: keep shared state simple, isolate platform code early, and invest in a predictable design system.', 1, TIMESTAMPTZ '2026-06-01 09:07:00+00', TIMESTAMPTZ '2026-06-01 09:07:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (2, 'ktor-api-patterns-that-keep-scaling', 'Ktor API Patterns That Keep Scaling', 'A small set of routing and service patterns that stay readable as the app grows.', 'This post walks through route grouping, request validation, and keeping the domain layer separate from transport concerns. The end result is easier testing and less controller logic.', 2, TIMESTAMPTZ '2026-06-02 10:14:00+00', TIMESTAMPTZ '2026-06-02 10:14:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (3, 'compose-desktop-for-fast-product-feedback', 'Compose Desktop for Fast Product Feedback', 'Use desktop builds to validate flows before spending time on mobile polish.', 'A desktop build gives you quick iteration when reviewing forms, list states, and navigation. It is especially useful while the backend contract is still moving.', 3, TIMESTAMPTZ '2026-06-03 11:21:00+00', TIMESTAMPTZ '2026-06-03 11:21:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (4, 'postgres-indexes-i-check-first', 'PostgreSQL Indexes I Check First', 'The first indexes I look for when an app starts feeling sluggish.', 'Before reaching for a rewrite, check the obvious queries: article feeds, tag lookups, author profiles, and favorites. Good indexes make manual testing feel much snappier.', 4, TIMESTAMPTZ '2026-06-04 12:28:00+00', TIMESTAMPTZ '2026-06-04 12:28:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (5, 'writing-tests-that-read-like-stories', 'Writing Tests That Read Like Stories', 'A pragmatic approach to test naming and fixtures.', 'The best tests for teams are the ones that describe behavior without making you reverse-engineer the setup. That usually means a few helpers, a clear arrange-act-assert structure, and stable test data.', 5, TIMESTAMPTZ '2026-06-05 13:35:00+00', TIMESTAMPTZ '2026-06-05 13:35:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (6, 'deploying-without-surprises', 'Deploying Without Surprises', 'A checklist for boring and reliable releases.', 'Keep environment variables explicit, make migrations part of the deployment, and verify health checks before exposing traffic. Boring deployments are the best deployments.', 6, TIMESTAMPTZ '2026-06-06 14:42:00+00', TIMESTAMPTZ '2026-06-06 14:42:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (7, 'designing-a-clean-article-feed', 'Designing a Clean Article Feed', 'How to keep list screens readable when content starts piling up.', 'A feed should answer three questions quickly: what is new, who wrote it, and why should I care. Clear typography, concise metadata, and good spacing do most of the work.', 7, TIMESTAMPTZ '2026-06-07 15:49:00+00', TIMESTAMPTZ '2026-06-07 15:49:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (8, 'auth-flows-users-do-not-hate', 'Auth Flows Users Do Not Hate', 'A few tiny details that make login and registration feel trustworthy.', 'Good auth UX is about feedback. Show validation early, keep error messages specific, and never make a user guess whether the request succeeded.', 8, TIMESTAMPTZ '2026-06-08 16:56:00+00', TIMESTAMPTZ '2026-06-08 16:56:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (9, 'favorite-buttons-are-not-just-eye-candy', 'Favorite Buttons Are Not Just Eye Candy', 'A tiny interaction that reveals a lot about product quality.', 'Favorites are easy to dismiss, but they become a useful signal for ranking, recommendations, and user engagement. They also make manual testing more satisfying.', 9, TIMESTAMPTZ '2026-06-09 08:03:00+00', TIMESTAMPTZ '2026-06-09 08:03:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (10, 'comments-that-actually-help-conversations', 'Comments That Actually Help Conversations', 'A lightweight comment model can still support real discussion.', 'If comments are going to be useful, keep them short to read, easy to sort, and simple to moderate. That is enough for a first pass and still pleasant to use.', 10, TIMESTAMPTZ '2026-06-10 09:10:00+00', TIMESTAMPTZ '2026-06-10 09:10:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (11, 'manual-testing-checklist-for-the-realworld-app', 'Manual Testing Checklist for the RealWorld App', 'A practical list for verifying the main user journeys.', 'Check registration, login, article creation, favoriting, following, commenting, and profile updates. With representative data, these flows are quick to sanity-check after each change.', 1, TIMESTAMPTZ '2026-06-11 10:17:00+00', TIMESTAMPTZ '2026-06-11 10:17:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (12, 'why-small-data-sets-still-matter', 'Why Small Data Sets Still Matter', 'You do not need production scale to catch most workflow bugs.', 'A handful of users, articles, follows, and comments is usually enough to exercise the important UI states. The trick is making the data feel believable and interconnected.', 2, TIMESTAMPTZ '2026-06-12 11:24:00+00', TIMESTAMPTZ '2026-06-12 11:24:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (13, 'from-empty-state-to-useful-dashboard', 'From Empty State to Useful Dashboard', 'How to keep the first run from feeling broken.', 'Empty states should explain what the app does and give a clear next action. That is especially important when manual testing starts on a fresh database.', 3, TIMESTAMPTZ '2026-06-13 12:31:00+00', TIMESTAMPTZ '2026-06-13 12:31:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (14, 'how-i-think-about-pagination', 'How I Think About Pagination', 'Simple pagination beats cleverness when the product is young.', 'Offset pagination is easy to reason about for testing, but the UI should still show enough context that users understand what they are seeing. Keep the controls obvious.', 4, TIMESTAMPTZ '2026-06-14 13:38:00+00', TIMESTAMPTZ '2026-06-14 13:38:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (15, 'the-case-for-deterministic-demo-content', 'The Case for Deterministic Demo Content', 'Stable fixtures make regressions much easier to spot.', 'If every refresh looks the same, it is easier to notice when a feature breaks. Deterministic demo content also makes screenshots and bug reports more useful.', 5, TIMESTAMPTZ '2026-06-15 14:45:00+00', TIMESTAMPTZ '2026-06-15 14:45:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (16, 'keeping-your-sql-readable', 'Keeping Your SQL Readable', 'Practical tips for making data scripts maintainable.', 'Readable SQL is about naming, formatting, and consistent ordering. When the seed file grows, structure matters more than trying to be clever.', 6, TIMESTAMPTZ '2026-06-16 15:52:00+00', TIMESTAMPTZ '2026-06-16 15:52:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (17, 'why-observability-should-start-early', 'Why Observability Should Start Early', 'Logs and metrics are part of the product, not just the ops story.', 'A small app still benefits from request tracing, error visibility, and timing metrics. Those signals help when a manual test does not behave as expected.', 7, TIMESTAMPTZ '2026-06-17 16:59:00+00', TIMESTAMPTZ '2026-06-17 16:59:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (18, 'shipping-small-ui-polishes', 'Shipping Small UI Polishes', 'Tiny improvements add up faster than big redesigns.', 'A handful of visual tweaks can make the whole app feel more complete: consistent spacing, better empty states, and a few helpful loading indicators.', 8, TIMESTAMPTZ '2026-06-18 08:06:00+00', TIMESTAMPTZ '2026-06-18 08:06:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (19, 'making-comment-threads-legible', 'Making Comment Threads Legible', 'A couple of structure choices can reduce visual noise.', 'The main challenge in comment design is density. Keep avatars, timestamps, and spacing consistent so the discussion reads easily.', 9, TIMESTAMPTZ '2026-06-19 09:13:00+00', TIMESTAMPTZ '2026-06-19 09:13:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (20, 'how-we-test-authentication-flows', 'How We Test Authentication Flows', 'The important bugs usually hide in the edges.', 'Login, logout, token persistence, and invalid credentials are the flows worth checking first. They are fast to test and usually reveal integration bugs quickly.', 10, TIMESTAMPTZ '2026-06-20 10:20:00+00', TIMESTAMPTZ '2026-06-20 10:20:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (21, 'using-follows-to-build-interesting-feeds', 'Using Follows to Build Interesting Feeds', 'A feed feels alive when relationships influence what appears.', 'Follow graphs are a quick way to make demo data feel real. They let you test both the global feed and the personalized feed with meaningful differences.', 1, TIMESTAMPTZ '2026-06-21 11:27:00+00', TIMESTAMPTZ '2026-06-21 11:27:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (22, 'designing-for-error-states', 'Designing for Error States', 'Failure screens deserve as much care as success screens.', 'Good error states tell the user what happened and what to do next. The nicer they are, the easier it is to test exceptional paths without confusion.', 2, TIMESTAMPTZ '2026-06-22 12:34:00+00', TIMESTAMPTZ '2026-06-22 12:34:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (23, 'why-content-variety-matters', 'Why Content Variety Matters', 'Different lengths and tones make the UI easier to evaluate.', 'If every article looks the same, you miss layout issues. Mix short and long titles, body lengths, and descriptions to exercise the screens properly.', 3, TIMESTAMPTZ '2026-06-23 13:41:00+00', TIMESTAMPTZ '2026-06-23 13:41:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (24, 'building-a-faster-feedback-loop', 'Building a Faster Feedback Loop', 'Make every manual test tell you something useful.', 'The shortest path from change to validation is the most valuable one. Good seed data keeps that loop tight by making each screen immediately testable.', 4, TIMESTAMPTZ '2026-06-24 14:48:00+00', TIMESTAMPTZ '2026-06-24 14:48:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (25, 'the-joy-of-clean-demo-data', 'The Joy of Clean Demo Data', 'Good demo data lowers the friction of doing the right thing.', 'When the content is believable and interconnected, manual testing becomes less mechanical and more like using the app for real. That is exactly what you want in a staging environment.', 5, TIMESTAMPTZ '2026-06-25 15:55:00+00', TIMESTAMPTZ '2026-06-25 15:55:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (26, 'why-seed-data-should-evolve', 'Why Seed Data Should Evolve', 'Static fixtures are useful, but they should not be frozen forever.', 'As the product grows, the data should reflect the flows you care about today. Expanding the seed set is one of the easiest ways to keep testing honest.', 6, TIMESTAMPTZ '2026-06-26 16:02:00+00', TIMESTAMPTZ '2026-06-26 16:02:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (27, 'the-importance-of-tag-discovery', 'The Importance of Tag Discovery', 'Tags are a small feature with a big effect on exploration.', 'A good tag list helps users discover related content and verify that metadata is being rendered correctly. It is a tiny but useful part of the demo experience.', 7, TIMESTAMPTZ '2026-06-27 08:09:00+00', TIMESTAMPTZ '2026-06-27 08:09:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (28, 'building-confidence-with-repetitive-testing', 'Building Confidence With Repetitive Testing', 'Repetition is only boring when the data is bad.', 'Stable, believable data makes repeat tests efficient. The more often you can run through the same flow without re-learning the setup, the faster bugs get found.', 8, TIMESTAMPTZ '2026-06-28 09:16:00+00', TIMESTAMPTZ '2026-06-28 09:16:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (29, 'why-comment-counts-matter', 'Why Comment Counts Matter', 'Even small counters are worth checking during manual QA.', 'Comment counts are a quick way to spot missing joins, broken updates, or stale caches. They are low effort to inspect and often surprisingly revealing.', 9, TIMESTAMPTZ '2026-06-29 10:23:00+00', TIMESTAMPTZ '2026-06-29 10:23:00+00') ON CONFLICT DO NOTHING;
INSERT INTO articles (article_id, slug, title, description, body, author_id, created_at, updated_at) VALUES (30, 'keeping-the-demo-app-predictable', 'Keeping the Demo App Predictable', 'Predictable systems are easier to exercise and easier to trust.', 'A demo app should be boring in the best possible way: clear login data, real relationships between records, and enough variety to make the UI feel alive.', 10, TIMESTAMPTZ '2026-06-30 11:30:00+00', TIMESTAMPTZ '2026-06-30 11:30:00+00') ON CONFLICT DO NOTHING;
